refentry.refsect1:
&reftitle.description;

 public booltidyNode::isHtml




 Gibt an, ob der Knoten ein Element-Knoten ist, jedoch nicht der Wurzelknoten des Dokuments.

&reftitle.changelog;





    &Version;
    &Description;





    7.3.24, 7.4.12

     Diese Funktion wurde korrigiert, sodass sie sich sinnvoll verhält. Zuvor
     wurde nahezu jeder Knoten als HTML-Knoten gemeldet.

  &reftitle.examples;



    HTML-Code aus einem gemischten HTML-Dokument extrahieren


<?php

$html = <<< HTML
<html><head>
<?php echo '<title>title</title>'; ?>
<# 
  /* JSTE code */
  alert('Hello World'); 
#>
</head>
<body>

<?php
  // PHP code
  echo 'hello world!';
?>

<%
  /* ASP code */
  response.write("Hello World!")
%>

<!-- Comments -->
Hello World
</body></html>
Outside HTML
HTML;


$tidy = tidy_parse_string($html);
$num = 0;

get_nodes($tidy->html());

function get_nodes($node) {
    // prüfen, ob der aktuelle Knoten vom gewünschten Typ ist
    if($node->isHtml()) {
        echo "\n\n# html node #" . ++$GLOBALS['num'] . "\n";
        echo $node->value;
    }

    // prüfen, ob der aktuelle Knoten Kindknoten hat
    if($node->hasChildren()) {
        foreach($node->child as $child) {
            get_nodes($child);
        }
    }
}

?>


